var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 샤레이드\\n<color=#ffd34c>제 6 난민지구</color>","JPN":"管理局直轄都市シャレード\\n<color=#ffd34c>第6難民地区</color>","ENG":"[[","TWN":"管理局直轄城市查雷德。\\n <color=#ffd34c>第6難民區。</color>","SCN":"管理局直辖城市查雷德。\\n <color=#ffd34c>第6难民区。</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"좋은 말 할 때 내놔. 왜 귀찮게 엉겨 붙고 그래?","JPN":"いつまでもまとわり付いてないで、優しくしてやってるうちに寄こしといた方がいいぞ？","ENG":"Hand it over while I'm being nice. Why make things harder for yourself?","TWN":"趁著我還能好好說話，快交出來。幹嘛這麼煩人地糾纏不休？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"싫어! 이건 동생들 약값이란 말이야!!","JPN":"いや！　これはみんなの薬代なの！！","ENG":"No! This is for my sisters' medicine!","TWN":"不行！這是給弟弟妹妹們買藥的錢！！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"아이고~. 이렇게 맞으면 네 약값만 더 들어요. 괜히 고집부리지 말고 힘 빼, 응?","JPN":"おいおい、殴られりゃおまえの分の薬代が増えるんだぜ？　意地張らねぇで手を放せ。な？","ENG":"Aww, sweet. Keep this up and you'll just rack up more medical bills. Don't be stubborn and give it here!","TWN":"哎喲～這樣打下去只會讓你的藥費增加。別固執了，鬆手，好嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"끄으…! 이거 놔, 놓으란 말이야!!","JPN":"くう……！　いやだ、絶対放さない！！","ENG":"Ugh...! Let go of me, I said let go!","TWN":"呃……！放開，叫你放開！！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"당신들! 거기서 뭐하는 거야?","JPN":"あんたたち！　そこで何をしているの？","ENG":"Hey, you two! What do you think you're doing?","TWN":"你們！在那裡幹什麼呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"엠마, 괜찮아? 어디 다친 덴 없어?","JPN":"エマ、大丈夫？　どこか怪我してない？","ENG":"Emma, are you okay? Did they hurt you?","TWN":"艾瑪，你沒事吧？有沒有受傷？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"레, 레이첼 언니이이이-!","JPN":"れ、レイチェルお姉ちゃーん！","ENG":"R-Rachel!","TWN":"瑞，瑞秋姊姊——！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"지금 이게 뭐하는 짓이에요? 다 큰 어른이 애들 상대로 부끄럽지도 않아요?","JPN":"いったい何なんですか？　大人が子供相手に、恥ずかしくないんですか？","ENG":"What do you think you're doing? Grown men picking on a kid. Aren't you ashamed?","TWN":"現在這是在幹什麼？都是成年人了，對孩子這樣不覺得羞愧嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"그야 부끄럽지. 다 큰 어른이 애 돈 하나 못 뜯고 있는데.","JPN":"そりゃあ恥ずかしいさ。いい大人がガキから金も取れずにいるなんてな。","ENG":"Sure, I'm ashamed—ashamed that I can't even squeeze some pocket change out of a brat.","TWN":"當然會覺得丟臉。都已經是成年人了，卻連小孩的錢都拿不到。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"뭐하고 있어? 빨리 이 녀석 안 치워?!","JPN":"なにしてんだ！　さっさとこのガキどかせ！","ENG":"What are you waiting for? Get this little pest outta my way!","TWN":"你幹什麼呢？還不趕緊解決掉這個傢伙？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"형님. 저 꼬마. 호라이즌이 대표로 있는 사채업장에서 일하는 애입니다.","JPN":"兄貴。このガキ、ホライズンが代表をやってる闇金事務所で働いてるやつです。","ENG":"Sir, that kid works for the loan shark Horizon.","TWN":"大哥。那個小孩是在地平線擔任代表的高利貸公司工作的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"응? 국제적으로 폭행 범죄를 일으킨 그 미치광이?","JPN":"あ？　あの国際的に暴行事件を起こした狂人のところか？","ENG":"Huh? That psycho who committed assault on an international scale?","TWN":"嗯？那個國際上製造暴力犯罪的瘋子？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"양아치들도 호라이즌 무서운 줄은 아나 보네. 그리고 사채업장이 아니라 투자기금이거든?","JPN":"チンピラでもホライズンは怖いのね。あと、闇金じゃなくてファンドって言ってくれる？","ENG":"So even thugs know to fear Horizon, huh? And we're not loan shark, we're an investment fund, thank you.","TWN":"連混混們都知道要怕地平線了啊。而且這不是高利貸公司，而是投資基金喔？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"무서운 꼴 보기 싫으면 빨리 줄행랑이나 치셔!","JPN":"痛い目見たくなかったら、さっさと逃げることね！","ENG":"If you don't wanna see something scary, I suggest you run while you can.","TWN":"不想看到可怕的場面就趕快逃跑吧！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"흐음… 그래, 그렇단 말이지?","JPN":"ふむ……なるほど、そういうことか？","ENG":"Hmm... Is that so?","TWN":"嗯…好吧，是這樣嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"잘됐네. 저년 인질로 잡으면 한몫 두둑이 챙길 수 있겠다, 야.","JPN":"ちょうどいい。あの女を人質に取れば一儲けできるんじゃねぇか？","ENG":"Well, even better. If we grab her as a hostage, we can cash in big time.","TWN":"太好了。抓住那個女人當人質的話，可以大賺一筆，嘿嘿。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐?","JPN":"な、何？","ENG":"W-what?!","TWN":"什，什麼？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"괜찮을까요? 들리는 소문으로는 관리국이랑 연줄이 있다는데.","JPN":"いいんですか？　噂だと管理局につてがあるらしいですけど。","ENG":"You sure that's a good idea? Rumor is she's got ties to the Administration.","TWN":"沒問題嗎？聽說她們和管理局有關係。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"넌 소문을 믿냐? 그냥 우리 같은 놈들 휘어잡으려고 적당히 흘리는 거야.","JPN":"でたらめだろ、そんな噂。俺たちみてぇなやつらを脅すために適当な話流してるに決まってる。","ENG":"You believe every rumor you hear? That's just smoke they blow to keep guys like us in line.","TWN":"你相信傳聞嗎？那只是為了控制我們這樣的人而故意散佈的消息罷了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"관리국이랑 연줄 있는 녀석이 뭐가 아쉬워서 난민지구에 투자기금을 차려?","JPN":"管理局につてがあるやつが難民地区でファンドなんか出すか。","ENG":"Someone with real connections to the Administration wouldn't be running some investment fund in the refugee district.","TWN":"和管理局有關係的人為什麼要在難民區設立投資基金？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 아저씨들 후회한다? 나 호라이즌 말고도 무서운 사람 많이 알거든?","JPN":"お、おじさんたち、後悔するよ？　アタシ、ホライズンの他にも怖い知り合いたくさんいるんだからね。","ENG":"Y-you guys are gonna regret this! I know plenty of scary people besides Horizon!","TWN":"啊，叔叔們後悔了嗎？我除了地平線之外，還認識很多可怕的人喔？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"총사대장님이랑, 중사님이랑, 해, 해적 언니랑, 그리고 또……!","JPN":"銃士隊長とか、軍曹とか、か、海賊のお姉ちゃんとか。あと……！","ENG":"Like General Musketeer, Sergeant! And a scary pirate lady! And, uh...!","TWN":"總隊長，中士，海，海盜姊姊，還有……！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};